 12→import org.wordpress.android.Constants
 13→import org.wordpress.android.R
 14→import org.wordpress.android.fluxc.model.SiteModel
 15→import org.wordpress.android.fluxc.model.scan.ScanStateModel
 16→import org.wordpress.android.fluxc.model.scan.ScanStateModel.State
 17→import org.wordpress.android.fluxc.store.ScanStore
 18→import org.wordpress.android.modules.UI_THREAD
 19→import org.wordpress.android.ui.jetpack.common.JetpackListItemState
 20→import org.wordpress.android.ui.jetpack.scan.ScanNavigationEvents.OpenFixThreatsConfirmationDialog
 21→import org.wordpress.android.ui.jetpack.scan.ScanNavigationEvents.ShowContactSupport
 22→import org.wordpress.android.ui.jetpack.scan.ScanNavigationEvents.ShowJetpackSettings
 23→import org.wordpress.android.ui.jetpack.scan.ScanNavigationEvents.ShowThreatDetails
 24→import org.wordpress.android.ui.jetpack.scan.ScanNavigationEvents.VisitVaultPressDashboard
