 26→import org.wordpress.android.ui.jetpack.scan.ScanViewModel.UiState.ErrorUiState
 27→import org.wordpress.android.ui.jetpack.scan.ScanViewModel.UiState.FullScreenLoadingUiState
 28→import org.wordpress.android.ui.jetpack.scan.builders.ScanStateListItemsBuilder
 29→import org.wordpress.android.ui.jetpack.scan.usecases.FetchFixThreatsStatusUseCase
 30→import org.wordpress.android.ui.jetpack.scan.usecases.FetchFixThreatsStatusUseCase.FetchFixThreatsState
 31→import org.wordpress.android.ui.jetpack.scan.usecases.FetchScanStateUseCase
 32→import org.wordpress.android.ui.jetpack.scan.usecases.FetchScanStateUseCase.FetchScanState
 33→import org.wordpress.android.ui.jetpack.scan.usecases.FixThreatsUseCase
 34→import org.wordpress.android.ui.jetpack.scan.usecases.FixThreatsUseCase.FixThreatsState
 35→import org.wordpress.android.ui.jetpack.scan.usecases.StartScanUseCase
 36→import org.wordpress.android.ui.jetpack.scan.usecases.StartScanUseCase.StartScanState
 37→import org.wordpress.android.ui.pages.SnackbarMessageHolder
 38→import org.wordpress.android.ui.utils.HtmlMessageUtils
 39→import org.wordpress.android.ui.utils.UiString
 40→import org.wordpress.android.ui.utils.UiString.UiStringRes
 41→import org.wordpress.android.ui.utils.UiString.UiStringResWithParams
 42→import org.wordpress.android.ui.utils.UiString.UiStringText
 43→import org.wordpress.android.util.analytics.ScanTracker
 44→import org.wordpress.android.util.analytics.ScanTracker.ErrorAction
 45→import org.wordpress.android.util.analytics.ScanTracker.ErrorCause
 46→import org.wordpress.android.util.analytics.ScanTracker.OnThreatItemClickSource
 47→import org.wordpress.android.viewmodel.Event
 48→import org.wordpress.android.viewmodel.ScopedViewModel
 49→import javax.inject.Inject
 50→import javax.inject.Named
 51→
 52→const val RETRY_DELAY = 300L
 53→
 54→@HiltViewModel
 55→class ScanViewModel @Inject constructor(
 56→    private val scanStateListItemsBuilder: ScanStateListItemsBuilder,
 57→    private val fetchScanStateUseCase: FetchScanStateUseCase,
 58→    private val startScanUseCase: StartScanUseCase,
 59→    private val fixThreatsUseCase: FixThreatsUseCase,
 60→    private val fetchFixThreatsStatusUseCase: FetchFixThreatsStatusUseCase,
 61→    private val scanStore: ScanStore,
 62→    private val scanTracker: ScanTracker,
 63→    private val htmlMessageUtils: HtmlMessageUtils,
 64→    @Named(UI_THREAD) private val mainDispatcher: CoroutineDispatcher
 65→) : ScopedViewModel(mainDispatcher) {
 66→    private var isStarted = false
 67→
 68→    private val _uiState: MutableLiveData<UiState> = MutableLiveData()
 69→    val uiState: LiveData<UiState> = _uiState
 70→
 71→    private val _snackbarEvents = MediatorLiveData<Event<SnackbarMessageHolder>>()
 72→    val snackbarEvents: LiveData<Event<SnackbarMessageHolder>> = _snackbarEvents
 73→
 74→    private val _navigationEvents = MediatorLiveData<Event<ScanNavigationEvents>>()
 75→    val navigationEvents: LiveData<Event<ScanNavigationEvents>> = _navigationEvents
 76→
 77→    private val fixableThreatIds
 78→        get() = scanStateModel?.threats
 79→            ?.filter { it.baseThreatModel.fixable != null }
 80→            ?.map { it.baseThreatModel.id }
 81→            ?: emptyList()
 82→
 83→    private var scanStateModel: ScanStateModel? = null
 84→    lateinit var site: SiteModel
 85→
 86→    fun start(site: SiteModel) {
 87→        if (isStarted) {
 88→            return
 89→        }
 90→        isStarted = true
 91→        this.site = site
 92→        init()
 93→    }
 94→
 95→    private fun init() {
 96→        updateUiState(FullScreenLoadingUiState)
 97→        launch {
 98→            scanStateModel = scanStore.getScanStateForSite(this@ScanViewModel.site)
 99→            scanStateModel?.let {
100→                if (fixableThreatIds.isNotEmpty()) fetchFixThreatsStatus(fixableThreatIds, isInvokedByUser = false)
101→            }
102→            fetchScanState(isInvokedFromInit = true)
103→        }
104→    }
105→
106→    private suspend fun fetchScanState(
107→        invokedByUser: Boolean = false,
108→        isRetry: Boolean = false,
109→        isInvokedFromInit: Boolean = false
110→    ) {
111→        if (isRetry) delay(RETRY_DELAY)
112→
113→        fetchScanStateUseCase.fetchScanState(site = site, startWithDelay = invokedByUser)
114→            .collect { state ->
115→                when (state) {
116→                    is FetchScanState.Success -> {
117→                        scanStateModel = state.scanStateModel
118→                        updateUiState(buildContentUiState(state.scanStateModel))
119→                        if (state.scanStateModel.state in listOf(State.UNAVAILABLE, State.UNKNOWN)) {
120→                            scanTracker.trackOnError(ErrorAction.FETCH_SCAN_STATE, ErrorCause.OTHER)
121→                            updateUiState(ErrorUiState.ScanRequestFailed(::onContactSupportClicked))
122→                        } else if (invokedByUser && state.scanStateModel.state == State.IDLE) {
123→                            showScanFinishedMessage(state.scanStateModel)
124→                        }
125→                    }
126→
127→                    is FetchScanState.Failure.NetworkUnavailable -> {
128→                        scanTracker.trackOnError(ErrorAction.FETCH_SCAN_STATE, ErrorCause.OFFLINE)
129→                        scanStateModel?.takeIf { !isInvokedFromInit }
130→                            ?.let {
131→                                updateSnackbarMessageEvent(UiStringRes(R.string.error_generic_network))
132→                            }
133→                            ?: updateUiState(ErrorUiState.NoConnection(::onRetryClicked))
134→                    }
135→
136→                    is FetchScanState.Failure.MultisiteNotSupported ->
137→                        updateUiState(ErrorUiState.MultisiteNotSupported)
138→
139→                    is FetchScanState.Failure.VaultPressActiveOnSite ->
140→                        updateUiState(ErrorUiState.VaultPressActiveOnSite(::onVisitVaultPressDashboardClicked))
141→
142→                    is FetchScanState.Failure.RemoteRequestFailure -> {
143→                        scanTracker.trackOnError(ErrorAction.FETCH_SCAN_STATE, ErrorCause.REMOTE)
144→                        scanStateModel?.takeIf { !isInvokedFromInit }
145→                            ?.let {
146→                                updateSnackbarMessageEvent(UiStringRes(R.string.request_failed_message))
147→                            }
148→                            ?: updateUiState(ErrorUiState.GenericRequestFailed(::onContactSupportClicked))
149→                    }
150→                }
151→            }
152→    }
153→
154→    private fun showScanFinishedMessage(scanStateModel: ScanStateModel) {
155→        val threatsCount = scanStateModel.threats?.size ?: 0
156→        val message = UiStringText(
157→            when (threatsCount) {
158→                0 -> htmlMessageUtils.getHtmlMessageFromStringFormatResId(
159→                    R.string.scan_finished_no_threats_found_message
160→                )
161→
162→                1 -> htmlMessageUtils.getHtmlMessageFromStringFormatResId(
163→                    R.string.scan_finished_potential_threats_found_message_singular
164→                )
165→
166→                else -> htmlMessageUtils.getHtmlMessageFromStringFormatResId(
167→                    R.string.scan_finished_potential_threats_found_message_plural,
168→                    "$threatsCount"
169→                )
170→            }
171→        )
172→        updateSnackbarMessageEvent(message)
173→    }
174→
175→    private fun startScan() {
176→        launch {
177→            startScanUseCase.startScan(site)
178→                .collect { state ->
179→                    when (state) {
180→                        is StartScanState.ScanningStateUpdatedInDb ->
181→                            updateUiState(buildContentUiState(state.model))
182→
183→                        is StartScanState.Success -> fetchScanState(invokedByUser = true)
184→
185→                        is StartScanState.Failure.NetworkUnavailable -> {
186→                            scanTracker.trackOnError(ErrorAction.SCAN, ErrorCause.OFFLINE)
187→                            updateSnackbarMessageEvent(UiStringRes(R.string.error_generic_network))
188→                        }
189→                        is StartScanState.Failure.RemoteRequestFailure -> {
190→                            scanTracker.trackOnError(ErrorAction.SCAN, ErrorCause.REMOTE)
191→                            updateUiState(ContentUiState(emptyList()))
192→                            updateUiState(ErrorUiState.ScanRequestFailed(::onContactSupportClicked))
193→                        }
194→                    }
195→                }
196→        }
197→    }
198→
199→    private fun fixAllThreats() {
200→        scanTracker.trackOnFixAllThreatsConfirmed()
201→        launch {
202→            when (fixThreatsUseCase.fixThreats(remoteSiteId = site.siteId, fixableThreatIds = fixableThreatIds)) {
203→                is FixThreatsState.Success -> {
204→                    val someOrAllThreatFixed = fetchFixThreatsStatus(fixableThreatIds, isInvokedByUser = true)
205→                    if (someOrAllThreatFixed) fetchScanState()
206→                }
207→                is FixThreatsState.Failure.NetworkUnavailable -> {
208→                    scanTracker.trackOnError(ErrorAction.FIX_ALL, ErrorCause.OFFLINE)
209→                    updateSnackbarMessageEvent(UiStringRes(R.string.error_generic_network))
210→                }
211→                is FixThreatsState.Failure.RemoteRequestFailure -> {
212→                    scanTracker.trackOnError(ErrorAction.FIX_ALL, ErrorCause.REMOTE)
213→                    updateSnackbarMessageEvent(UiStringRes(R.string.threat_fix_all_error_message))
214→                }
215→            }
216→        }
217→    }
218→
219→    private suspend fun fetchFixThreatsStatus(fixableThreatIds: List<Long>, isInvokedByUser: Boolean): Boolean {
220→        var someOrAllThreatFixed = false
221→
222→        @StringRes var messageRes: Int? = null
223→        fetchFixThreatsStatusUseCase.fetchFixThreatsStatus(
224→            remoteSiteId = site.siteId,
225→            fixableThreatIds = fixableThreatIds
226→        ).collect { status ->
227→            var fixingThreatIds = emptyList<Long>()
228→            when (status) {
229→                is FetchFixThreatsState.NotStarted -> { // Do nothing
230→                }
231→                is FetchFixThreatsState.InProgress -> {
232→                    fixingThreatIds = status.threatIds
233→                }
234→                is FetchFixThreatsState.Complete -> {
235→                    someOrAllThreatFixed = true
236→                    messageRes = if (status.fixedThreatsCount == 1) {
237→                        R.string.threat_fix_all_status_success_message_singular
238→                    } else R.string.threat_fix_all_status_success_message_plural
239→                }
240→                is FetchFixThreatsState.Failure.NetworkUnavailable -> {
241→                    scanTracker.trackOnError(ErrorAction.FETCH_FIX_THREAT_STATUS, ErrorCause.OFFLINE)
242→                    messageRes = R.string.error_generic_network
243→                }
244→                is FetchFixThreatsState.Failure.RemoteRequestFailure -> {
245→                    scanTracker.trackOnError(ErrorAction.FETCH_FIX_THREAT_STATUS, ErrorCause.REMOTE)
246→                    messageRes = R.string.threat_fix_all_status_error_message
247→                }
248→                is FetchFixThreatsState.Failure.FixFailure -> {
249→                    if (status.mightBeMissingCredentials) {
250→                        scanTracker.trackOnError(ErrorAction.FETCH_FIX_THREAT_STATUS, ErrorCause.ALL_THREATS_NOT_FIXED)
251→                    } else {
252→                        scanTracker.trackOnError(ErrorAction.FETCH_FIX_THREAT_STATUS, ErrorCause.OTHER)
253→                    }
254→                    if (!status.containsOnlyErrors) {
255→                        someOrAllThreatFixed = true
256→                    } else {
257→                        messageRes = R.string.threat_fix_all_status_error_message
258→                    }
259→                }
260→            }
261→
262→            val shouldUpdateUi = status is FetchFixThreatsState.InProgress || status is FetchFixThreatsState.Complete
263→            if (shouldUpdateUi) {
264→                updateUiState(
265→                    buildContentUiState(model = requireNotNull(scanStateModel), fixingThreatIds = fixingThreatIds)
266→                )
267→            }
268→
269→            if (isInvokedByUser) messageRes?.let { updateSnackbarMessageEvent(UiStringRes(it)) }
270→        }
271→
272→        return someOrAllThreatFixed
273→    }
274→
275→    private fun onRetryClicked() {
276→        launch { fetchScanState(isRetry = true) }
277→    }
278→
279→    private fun onVisitVaultPressDashboardClicked() {
280→        updateNavigationEvent(VisitVaultPressDashboard(Constants.URL_VISIT_VAULTPRESS_DASHBOARD))
281→    }
282→
283→    private fun onContactSupportClicked() {
284→        updateNavigationEvent(ShowContactSupport(site))
285→    }
286→
287→    private fun onScanButtonClicked() {
288→        scanTracker.trackOnScanButtonClicked()
289→        startScan()
290→    }
291→
292→    private fun onFixAllButtonClicked() {
293→        scanTracker.trackOnFixAllThreatsButtonClicked()
294→        updateNavigationEvent(
295→            OpenFixThreatsConfirmationDialog(
296→                title = UiStringRes(R.string.threat_fix_all_warning_title),
297→                message = if (fixableThreatIds.size > 1) {
298→                    UiStringResWithParams(
299→                        R.string.threat_fix_all_confirmation_message_plural,
300→                        listOf(UiStringText("${fixableThreatIds.size}"))
301→                    )
302→                } else UiStringRes(R.string.threat_fix_all_confirmation_message_singular),
303→                okButtonAction = this@ScanViewModel::fixAllThreats
304→            )
305→        )
306→    }
307→
308→    private fun onThreatItemClicked(threatId: Long) {
309→        launch {
310→            scanTracker.trackOnThreatItemClicked(threatId, OnThreatItemClickSource.SCANNER)
