 55→public class SelectCategoriesActivity extends LocaleAwareActivity {
 56→    public static final String KEY_SELECTED_CATEGORY_IDS = "KEY_SELECTED_CATEGORY_IDS";
 57→
 58→    private ListView mListView;
 59→    private TextView mEmptyView;
 60→    private ListScrollPositionManager mListScrollPositionManager;
 61→    private SwipeToRefreshHelper mSwipeToRefreshHelper;
 62→    private HashSet<Long> mSelectedCategories;
 63→    private ArrayList<CategoryNode> mCategoryLevels;
 64→    private LongSparseArray<Integer> mCategoryRemoteIdsToListPositions = new LongSparseArray<>();
 65→    private SiteModel mSite;
 66→
 67→    @Inject SiteStore mSiteStore;
 68→    @Inject PostStore mPostStore;
 69→    @Inject TaxonomyStore mTaxonomyStore;
 70→    @Inject Dispatcher mDispatcher;
 71→
 72→    @Override
 73→    public void onCreate(@Nullable Bundle savedInstanceState) {
 74→        super.onCreate(savedInstanceState);
 75→        ((WordPress) getApplication()).component().inject(this);
 76→
 77→        OnBackPressedCallback callback = new OnBackPressedCallback(true) {
 78→            @Override
 79→            public void handleOnBackPressed() {
 80→                saveAndFinish();
 81→                CompatExtensionsKt.onBackPressedCompat(getOnBackPressedDispatcher(), this);
 82→            }
 83→        };
 84→        getOnBackPressedDispatcher().addCallback(this, callback);
 85→
 86→        mDispatcher.register(this);
 87→
 88→        if (savedInstanceState == null) {
 89→            mSite = (SiteModel) getIntent().getSerializableExtra(WordPress.SITE);
 90→        } else {
 91→            mSite = (SiteModel) savedInstanceState.getSerializable(WordPress.SITE);
 92→        }
 93→        if (mSite == null) {
 94→            ToastUtils.showToast(this, R.string.blog_not_found, ToastUtils.Duration.SHORT);
 95→            finish();
 96→            return;
 97→        }
 98→
 99→        setContentView(R.layout.select_categories);
100→
101→        Toolbar toolbar = findViewById(R.id.toolbar_main);
102→        setSupportActionBar(toolbar);
103→        ActionBar actionBar = getSupportActionBar();
104→        if (actionBar != null) {
105→            actionBar.setHomeButtonEnabled(true);
106→            actionBar.setDisplayHomeAsUpEnabled(true);
107→        }
108→
109→        setTitle(getResources().getString(R.string.select_categories));
110→
111→        mListView = (ListView) findViewById(android.R.id.list);
112→        mListScrollPositionManager = new ListScrollPositionManager(mListView, false);
113→        mListView.setChoiceMode(ListView.CHOICE_MODE_MULTIPLE);
114→        mListView.setItemsCanFocus(false);
115→
116→        mEmptyView = (TextView) findViewById(R.id.empty_view);
117→        mListView.setEmptyView(mEmptyView);
118→
119→        mSelectedCategories = new HashSet<>();
120→
121→        Bundle extras = getIntent().getExtras();
122→        if (extras != null) {
123→            if (extras.containsKey(EXTRA_POST_LOCAL_ID)) {
124→                int localPostId = extras.getInt(EXTRA_POST_LOCAL_ID);
125→                PostModel post = mPostStore.getPostByLocalPostId(localPostId);
126→                if (post != null) {
127→                    for (Long categoryId : post.getCategoryIdList()) {
128→                        mSelectedCategories.add(categoryId);
129→                    }
130→                }
131→            }
132→        }
133→
134→        // swipe to refresh setup
135→        mSwipeToRefreshHelper = buildSwipeToRefreshHelper(
136→                (CustomSwipeRefreshLayout) findViewById(R.id.ptr_layout),
137→                new RefreshListener() {
138→                    @Override
139→                    public void onRefreshStarted() {
140→                        if (!NetworkUtils.checkConnection(getBaseContext())) {
141→                            mSwipeToRefreshHelper.setRefreshing(false);
142→                            return;
143→                        }
144→                        refreshCategories();
145→                    }
146→                }
147→        );
148→
149→        populateCategoryList();
150→
151→        if (NetworkUtils.isNetworkAvailable(this)) {
152→            mEmptyView.setText(R.string.empty_list_default);
153→            if (isCategoryListEmpty()) {
154→                refreshCategories();
155→            }
156→        } else {
157→            mEmptyView.setText(R.string.no_network_title);
158→        }
159→    }
