171→    private void populateCategoryList() {
172→        CategoryNode categoryTree = CategoryNode.createCategoryTreeFromList(mTaxonomyStore.getCategoriesForSite(mSite));
173→        mCategoryLevels = CategoryNode.getSortedListOfCategoriesFromRoot(categoryTree);
174→        for (int i = 0; i < mCategoryLevels.size(); i++) {
175→            mCategoryRemoteIdsToListPositions.put(mCategoryLevels.get(i).getCategoryId(), i);
176→        }
177→
178→        CategoryArrayAdapter categoryAdapter = new CategoryArrayAdapter(this, R.layout.categories_row, mCategoryLevels);
179→        mListView.setAdapter(categoryAdapter);
180→        if (mSelectedCategories != null) {
181→            for (Long selectedCategory : mSelectedCategories) {
182→                if (mCategoryRemoteIdsToListPositions.get(selectedCategory) != null) {
183→                    mListView.setItemChecked(mCategoryRemoteIdsToListPositions.get(selectedCategory), true);
184→                }
185→            }
186→        }
187→        mListScrollPositionManager.restoreScrollOffset();
188→    }
