190→    private void showAddCategoryFragment() {
191→        FragmentTransaction ft = getSupportFragmentManager().beginTransaction();
192→        Fragment prev = getSupportFragmentManager().findFragmentByTag("dialog");
193→        if (prev != null) {
194→            ft.remove(prev);
195→        }
196→        ft.addToBackStack(null);
197→
198→        // Create and show the dialog.
199→        AddCategoryFragment newFragment = AddCategoryFragment.Companion.newInstance(mSite);
200→        newFragment.show(ft, "dialog");
201→    }
