217→    public void categoryAdded(TermModel newCategory) {
218→        if (!NetworkUtils.checkConnection(this)) {
219→            mEmptyView.setText(R.string.no_network_title);
220→            return;
221→        }
222→        // Save selected categories
223→        updateSelectedCategoryList();
224→        mListScrollPositionManager.saveScrollOffset();
225→
226→        mSwipeToRefreshHelper.setRefreshing(true);
227→        RemoteTermPayload payload = new RemoteTermPayload(newCategory, mSite);
228→        mDispatcher.dispatch(TaxonomyActionBuilder.newPushTermAction(payload));
229→    }
230→
231→    @Override
232→    public boolean onOptionsItemSelected(@NonNull MenuItem item) {
233→        int itemId = item.getItemId();
234→        if (itemId == R.id.menu_new_category) {
235→            if (NetworkUtils.checkConnection(this)) {
236→                showAddCategoryFragment();
237→            }
238→            return true;
239→        } else if (itemId == android.R.id.home) {
240→            saveAndFinish();
241→            return true;
242→        }
243→
244→        return super.onOptionsItemSelected(item);
245→    }
246→
247→    private void refreshCategories() {
248→        mSwipeToRefreshHelper.setRefreshing(true);
249→        mListScrollPositionManager.saveScrollOffset();
250→        updateSelectedCategoryList();
251→        mDispatcher.dispatch(TaxonomyActionBuilder.newFetchCategoriesAction(mSite));
252→    }
253→
254→    private void updateSelectedCategoryList() {
255→        SparseBooleanArray selectedItems = mListView.getCheckedItemPositions();
256→        for (int i = 0; i < selectedItems.size(); i++) {
257→            if (selectedItems.keyAt(i) >= mCategoryLevels.size()) {
258→                continue;
259→            }
260→
261→            long categoryRemoteId = mCategoryLevels.get(selectedItems.keyAt(i)).getCategoryId();
262→            if (selectedItems.get(selectedItems.keyAt(i))) {
263→                mSelectedCategories.add(categoryRemoteId);
264→            } else {
265→                mSelectedCategories.remove(categoryRemoteId);
266→            }
267→        }
268→    }
269→
270→    private void saveAndFinish() {
271→        Bundle bundle = new Bundle();
272→        updateSelectedCategoryList();
273→        bundle.putSerializable(KEY_SELECTED_CATEGORY_IDS, new ArrayList<>(mSelectedCategories));
274→        Intent mIntent = new Intent();
275→        mIntent.putExtras(bundle);
276→        setResult(RESULT_OK, mIntent);
277→        finish();
278→    }
279→
280→    @SuppressWarnings("unused")
281→    @Subscribe(threadMode = ThreadMode.MAIN)
282→    public void onTaxonomyChanged(OnTaxonomyChanged event) {
283→        switch (event.causeOfChange) {
284→            case FETCH_CATEGORIES:
285→                mSwipeToRefreshHelper.setRefreshing(false);
286→
287→                if (event.isError()) {
288→                    if (!isFinishing()) {
289→                        ToastUtils.showToast(SelectCategoriesActivity.this, R.string.category_refresh_error,
290→                                             Duration.LONG);
291→                    }
292→                } else {
293→                    populateCategoryList();
294→                }
295→                break;
296→        }
297→    }
298→
299→    @SuppressWarnings("unused")
300→    @Subscribe(threadMode = ThreadMode.MAIN)
301→    public void onTermUploaded(OnTermUploaded event) {
302→        mSwipeToRefreshHelper.setRefreshing(false);
303→
304→        if (event.isError()) {
305→            if (!isFinishing()) {
306→                ToastUtils.showToast(SelectCategoriesActivity.this, R.string.adding_cat_failed, Duration.LONG);
307→            }
308→        } else {
309→            mSelectedCategories.add(event.term.getRemoteTermId());
310→            populateCategoryList();
311→            if (!isFinishing()) {
312→                ToastUtils.showToast(SelectCategoriesActivity.this, R.string.adding_cat_success, Duration.SHORT);
313→            }
314→        }
315→    }
316→}
