 92→    private val sortedWpComThemes: List<ThemeModel>
 93→        get() {
 94→            val wpComThemes = themeStore.wpComThemes
 95→
 96→            // first thing is to remove all external (partner) themes from the themes list since we do not support them
 97→            removeNonActiveExternalThemes(wpComThemes)
 98→
 99→            // then attempt to find the active theme and move it to the front of the list
100→            moveActiveThemeToFront(wpComThemes)
101→
102→            // then remove all premium themes from the list with an exception for the active theme
103→            if (!shouldShowPremiumThemes()) {
104→                removeNonActivePremiumThemes(wpComThemes)
105→            }
