108→    private val sortedJetpackThemes: List<ThemeModel>
109→        get() {
110→            val wpComThemes = themeStore.wpComThemes
111→            val uploadedThemes = themeStore.getThemesForSite(requireNotNull(site))
112→
113→            // remove all external (partner) themes from themes list since we do not support them
114→            removeNonActiveExternalThemes(wpComThemes)
115→
116→            // put the active theme at the top of the uploaded themes list
117→            moveActiveThemeToFront(uploadedThemes)
118→
119→            // remove all premium themes from the WP.com themes list
120→            removeNonActivePremiumThemes(wpComThemes)
121→
122→            // remove uploaded themes from WP.com themes list (including active theme)
123→            removeDuplicateThemes(wpComThemes, uploadedThemes)
124→            val allThemes: MutableList<ThemeModel> = ArrayList()
125→            allThemes.addAll(uploadedThemes)
126→            allThemes.addAll(wpComThemes)
127→            return allThemes
128→        }
