321→            return
322→        }
323→
324→        val hasThemes = adapter.unfilteredCount > 0
325→        val hasVisibleThemes = adapter.count > 0
326→        val hasNoMatchingThemes = hasThemes && !hasVisibleThemes
327→
328→        binding?.emptyView?.visibility = if (!hasThemes) View.VISIBLE else View.GONE
329→        if (!hasThemes && !NetworkUtils.isNetworkAvailable(activity)) {
330→            binding?.textEmpty?.setText(R.string.no_network_title)
331→        }
332→        binding?.themeListview?.visibility = if (hasVisibleThemes) View.VISIBLE else View.GONE
333→        binding?.actionableEmptyView?.visibility = if (hasNoMatchingThemes) View.VISIBLE else View.GONE
334→    }
