405→    private inner class ThemeDataSetObserver : DataSetObserver() {
406→        override fun onChanged() {
407→            updateDisplay()
408→        }
409→
410→        override fun onInvalidated() {
411→            updateDisplay()
412→        }
413→    }
414→
415→    companion object {
416→        @JvmField
417→        val TAG: String = ThemeBrowserFragment::class.java.name
418→        private const val KEY_LAST_SEARCH = "last_search"
419→
420→        @JvmStatic
421→        fun newInstance(site: SiteModel): ThemeBrowserFragment {
422→            val fragment = ThemeBrowserFragment()
423→            val bundle = Bundle()
424→            bundle.putSerializable(WordPress.SITE, site)
425→            fragment.arguments = bundle
426→            return fragment
427→        }
428→    }
