 40→class HistoryViewModel @Inject constructor(
 41→    private val dispatcher: Dispatcher,
 42→    private val resourceProvider: ResourceProvider,
 43→    private val networkUtils: NetworkUtilsWrapper,
 44→    private val postStore: PostStore,
 45→    @Named(UI_THREAD) uiDispatcher: CoroutineDispatcher,
 46→    @Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher,
 47→    private val connectionStatus: LiveData<ConnectionStatus>
 48→) : ScopedViewModel(uiDispatcher) {
 49→    enum class HistoryListStatus {
 50→        DONE,
 51→        ERROR,
 52→        NO_NETWORK,
 53→        FETCHING
 54→    }
 55→
 56→    private val _listStatus = MutableLiveData<HistoryListStatus>()
 57→    val listStatus: LiveData<HistoryListStatus>
 58→        get() = _listStatus
 59→
 60→    private val _revisions = MutableLiveData<List<HistoryListItem>>()
 61→    val revisions: LiveData<List<HistoryListItem>>
 62→        get() = _revisions
 63→
 64→    private val _showDialog = SingleLiveEvent<ShowDialogEvent>()
 65→    val showDialog: LiveData<ShowDialogEvent>
 66→        get() = _showDialog
 67→
 68→    private var isStarted = false
 69→
 70→    private val revisionsList: MutableList<Revision> = mutableListOf()
 71→    private lateinit var site: SiteModel
 72→
 73→    private val _post = MutableLiveData<PostModel?>()
 74→    val post: LiveData<PostModel?> = _post
 75→
 76→    private val lifecycleOwner = object : LifecycleOwner {
 77→        val lifecycleRegistry = LifecycleRegistry(this)
 78→        override val lifecycle: Lifecycle = lifecycleRegistry
 79→    }
 80→
 81→    init {
 82→        lifecycleOwner.lifecycleRegistry.currentState = Lifecycle.State.CREATED
 83→        dispatcher.register(this)
 84→    }
 85→
 86→    fun create(localPostId: Int, site: SiteModel) {
 87→        if (isStarted) {
 88→            return
 89→        }
 90→        isStarted = true
 91→        this.site = site
 92→        connectionStatus.observe(lifecycleOwner) {
 93→            if (it == AVAILABLE) {
 94→                fetchRevisions()
 95→            }
 96→        }
 97→        launch {
 98→            val post: PostModel? = withContext(bgDispatcher) {
 99→                postStore.getPostByLocalPostId(localPostId)
100→            }
101→
102→            revisionsList.clear()
103→            _revisions.postValue(emptyList())
104→
105→            this@HistoryViewModel._post.postValue(post)
106→
107→            fetchRevisions()
108→
109→            lifecycleOwner.lifecycleRegistry.currentState = Lifecycle.State.STARTED
110→        }
111→    }
112→
113→    private fun createRevisionsList(revisions: List<RevisionModel>) {
114→        var revisionAuthorsId = ArrayList<String>()
115→        revisions.forEach {
116→            if (!TextUtils.isEmpty(it.postAuthorId)) {
117→                revisionAuthorsId.add(it.postAuthorId!!)
118→            }
119→        }
120→
121→        revisionAuthorsId = ArrayList(revisionAuthorsId.distinct())
122→        _revisions.postValue(getHistoryListItemsFromRevisionModels(revisions))
123→
124→        if (revisionAuthorsId.isNotEmpty()) {
125→            fetchRevisionAuthorDetails(revisionAuthorsId)
126→        }
127→    }
128→
129→    private fun fetchRevisionAuthorDetails(authorsId: List<String>) {
130→        PeopleUtils.fetchRevisionAuthorsDetails(site, authorsId, object : FetchUsersCallback {
131→            override fun onSuccess(peopleList: List<Person>, isEndOfList: Boolean) {
132→                val existingRevisions = _revisions.value ?: return
133→                val updatedRevisions = mutableListOf<HistoryListItem>()
134→                revisionsList.clear()
135→
136→                existingRevisions.forEach { existingRevision ->
137→                    var mutableRevision = existingRevision
138→
139→                    if (mutableRevision is Revision) {
140→                        // we shouldn't directly update items in MutableLiveData, as they will be updated downstream
141→                        // and DiffUtil will not catch this change
142→                        mutableRevision = mutableRevision.copy()
143→
144→                        val person = peopleList.firstOrNull { it.personID.toString() == mutableRevision.postAuthorId }
145→                        if (person != null) {
146→                            mutableRevision.authorAvatarURL = person.avatarUrl
147→                            mutableRevision.authorDisplayName = person.displayName
148→                        }
149→
150→                        revisionsList.add(mutableRevision)
151→                    }
152→
153→                    updatedRevisions.add(mutableRevision)
154→                }
155→
156→                _revisions.postValue(updatedRevisions)
157→            }
158→
159→            override fun onError() {
160→                AppLog.e(T.API, "Can't fetch details of revision authors")
161→            }
162→        })
163→    }
164→
165→    private fun fetchRevisions() {
166→        val post = this.post.value
167→
168→        if (post != null) {
169→            _listStatus.value = HistoryListStatus.FETCHING
170→            val payload = FetchRevisionsPayload(post, site)
171→            dispatcher.dispatch(PostActionBuilder.newFetchRevisionsAction(payload))
172→        } else {
173→            _listStatus.value = HistoryListStatus.DONE
174→            createRevisionsList(emptyList())
175→        }
176→    }
177→
178→    private fun getHistoryListItemsFromRevisionModels(revisions: List<RevisionModel>): List<HistoryListItem> {
179→        val items = mutableListOf<HistoryListItem>()
180→
181→        revisions.forEach {
182→            val item = Revision(it)
183→            val last = items.lastOrNull() as? Revision
184→
185→            if (item.formattedDate != last?.formattedDate) {
186→                items.add(HistoryListItem.Header(item.formattedDate))
187→            }
188→
189→            items.add(item)
190→            revisionsList.add(item)
191→        }
192→
193→        if (revisions.isNotEmpty()) {
194→            val last = items.last() as Revision
195→            val footer = if (post.value?.isPage == true) {
196→                resourceProvider.getString(R.string.history_footer_page, last.formattedDate, last.formattedTime)
197→            } else {
198→                resourceProvider.getString(R.string.history_footer_post, last.formattedDate, last.formattedTime)
199→            }
200→            items.add(HistoryListItem.Footer(footer))
201→        }
202→
203→        return items
204→    }
205→
206→    override fun onCleared() {
207→        dispatcher.unregister(this)
208→        lifecycleOwner.lifecycleRegistry.currentState = Lifecycle.State.DESTROYED
209→        super.onCleared()
210→    }
211→
212→    fun onItemClicked(item: HistoryListItem) {
213→        if (item is Revision) {
214→            _showDialog.value = ShowDialogEvent(item, revisionsList)
215→        }
216→    }
217→
218→    fun onPullToRefresh() {
219→        fetchRevisions()
220→    }
221→
222→    private fun saveRevisionsToLocalDB(post: PostModel, revisions: List<RevisionModel>) {
223→        revisions.forEach {
224→            postStore.setLocalRevision(it, site, post)
225→        }
226→    }
227→
228→    private fun removeRevisionsFromLocalDB(post: PostModel) {
229→        postStore.deleteLocalRevisionOfAPostOrPage(post)
230→    }
