232→    data class ShowDialogEvent(val historyListItem: HistoryListItem, val revisionsList: List<Revision>)
233→
234→    @Suppress("unused")
235→    @Subscribe(threadMode = ThreadMode.MAIN)
236→    fun onRevisionsFetched(event: OnRevisionsFetched) {
237→        if (event.isError) {
238→            AppLog.e(T.API, "An error occurred while fetching History revisions")
239→            if (networkUtils.isNetworkAvailable()) {
240→                _listStatus.value = HistoryListStatus.ERROR
241→            } else {
242→                _listStatus.value = HistoryListStatus.NO_NETWORK
243→            }
244→        } else {
245→           launch(bgDispatcher) {
246→               _listStatus.postValue(HistoryListStatus.DONE)
247→               createRevisionsList(event.revisionsModel.revisions)
248→               removeRevisionsFromLocalDB(event.post)
249→               saveRevisionsToLocalDB(event.post, event.revisionsModel.revisions)
250→           }
251→        }
252→    }
253→}
