 35→) : ViewModel() {
 36→    private var isStarted = false
 37→    private lateinit var currentLanguage: String
 38→    private var parentViewModel: ReaderViewModel? = null
 39→
 40→    private var entryPoint = EntryPoint.DISCOVER
 41→    private var userTags = ReaderTagList()
 42→
 43→    private val _uiState: MutableLiveData<UiState> = MutableLiveData()
 44→    val uiState: LiveData<UiState> = _uiState
 45→
 46→    private val _snackbarEvents = MediatorLiveData<Event<SnackbarMessageHolder>>()
 47→    val snackbarEvents: LiveData<Event<SnackbarMessageHolder>> = _snackbarEvents
 48→
 49→    private val _closeReaderInterests = MutableLiveData<Event<Unit>>()
 50→    val closeReaderInterests: LiveData<Event<Unit>> = _closeReaderInterests
