 52→    private var userTagsFetchedSuccessfully = false
 53→
 54→    fun start(
 55→        currentLanguage: String,
 56→        parentViewModel: ReaderViewModel?,
 57→        entryPoint: EntryPoint
 58→    ) {
 59→        if (isStarted && this.currentLanguage == currentLanguage) {
 60→            return
 61→        }
 62→        isStarted = true
 63→        this.currentLanguage = currentLanguage
 64→        this.parentViewModel = parentViewModel
 65→        this.entryPoint = entryPoint
 66→        parentViewModel?.dismissQuickStartSnackbarIfNeeded()
 67→        loadUserTags()
 68→    }
