 70→    private fun loadUserTags() {
 71→        updateUiState(InitialLoadingUiState)
 72→        viewModelScope.launch {
 73→            when (val result = readerTagRepository.getUserTags()) {
 74→                is ReaderRepositoryCommunication.SuccessWithData<*> -> {
 75→                    userTagsFetchedSuccessfully = true
 76→                    userTags = result.data as ReaderTagList
 77→                    when (entryPoint) {
 78→                        EntryPoint.DISCOVER -> checkAndLoadInterests(userTags)
 79→                        EntryPoint.SETTINGS -> loadInterests(userTags)
 80→                    }
 81→                }
 82→                is ReaderRepositoryCommunication.Error -> {
 83→                    if (result is ReaderRepositoryCommunication.Error.NetworkUnavailable) {
 84→                        updateUiState(ConnectionErrorUiState)
 85→                    } else if (result is ReaderRepositoryCommunication.Error.RemoteRequestFailure) {
 86→                        updateUiState(RequestFailedErrorUiState)
 87→                    }
 88→                }
 89→                ReaderRepositoryCommunication.Started -> Unit // Do nothing
 90→                ReaderRepositoryCommunication.Success -> Unit // Do nothing
 91→            }
 92→        }
 93→    }
 94→
 95→    private fun checkAndLoadInterests(userTags: ReaderTagList) {
 96→        // since new users have the dailyprompt tag followed by default, we need to ignore them when
 97→        // checking if the user has any tags followed, so we show the onboarding state (ShowNoFollowedTags)
 98→        if (userTags.filterNot { it.tagSlug == BLOGGING_PROMPT_TAG }.isEmpty()) {
 99→            loadInterests(userTags)
100→        } else {
101→            parentViewModel?.onCloseReaderInterests()
102→        }
103→    }
