107→        viewModelScope.launch {
108→            val newUiState: UiState? = when (val result = readerTagRepository.getInterests()) {
109→                is ReaderRepositoryCommunication.SuccessWithData<*> -> {
110→                    readerTracker.track(AnalyticsTracker.Stat.SELECT_INTERESTS_SHOWN)
111→
112→                    val tags = (result.data as ReaderTagList).filter { checkAndExcludeTag(userTags, it) }
113→                    val distinctTags = ReaderTagList().apply { addAll(tags.distinctBy { it.tagSlug }) }
114→                    when (entryPoint) {
115→                        EntryPoint.DISCOVER -> ContentUiState(
116→                            interestsUiState = transformToInterestsUiState(distinctTags),
117→                            interests = distinctTags,
118→                            doneButtonUiState = DoneButtonDisabledUiState(),
119→                            titleVisible = true
120→                        )
121→                        EntryPoint.SETTINGS -> ContentUiState(
122→                            interestsUiState = transformToInterestsUiState(distinctTags),
123→                            interests = distinctTags,
124→                            doneButtonUiState = DoneButtonDisabledUiState(R.string.reader_btn_done),
125→                            titleVisible = false
126→                        )
127→                    }
128→                }
129→                is ReaderRepositoryCommunication.Error.NetworkUnavailable -> {
130→                    ConnectionErrorUiState
131→                }
132→                is ReaderRepositoryCommunication.Error.RemoteRequestFailure -> {
133→                    RequestFailedErrorUiState
134→                }
135→                else -> {
136→                    null
137→                }
138→            }
139→
140→            newUiState?.let {
141→                updateUiState(it)
142→            }
143→        }
144→    }
