146→    private fun checkAndExcludeTag(userTags: ReaderTagList, tag: ReaderTag): Boolean {
147→        var contain = false
148→        userTags.forEach { excludedTag ->
149→            if (excludedTag.tagSlug.equals(tag.tagSlug)) {
150→                contain = true
151→                return@forEach
152→            }
153→        }
154→        return !contain
155→    }
