390→    /*
391→      * this method has two purposes: (1) make sure media that is being deleted still has the right UploadState,
392→      * as it may have been overwritten by a refresh while deletion was still in progress, (2) remove any local
393→      * files (ie: media not uploaded yet) that no longer exist (in case user deleted them from the device)
394→      */
395→    private void ensureCorrectState(List<MediaModel> mediaModels) {
396→        if (isAdded() && getActivity() instanceof MediaBrowserActivity) {
397→            // we only need to check the deletion state if media are currently being deleted
398→            MediaDeleteService service = ((MediaBrowserActivity) getActivity()).getMediaDeleteService();
399→            boolean checkDeleteState = service != null && service.isAnyMediaBeingDeleted();
400→
401→            // note we count backwards so we can remove from the list
402→            for (int i = mediaModels.size() - 1; i >= 0; i--) {
403→                MediaModel media = mediaModels.get(i);
404→                // ensure correct upload state for media being deleted
405→                if (checkDeleteState && service.isMediaBeingDeleted(media)) {
406→                    media.setUploadState(MediaUploadState.DELETING);
407→                }
408→
409→                // remove local media that no longer exists
410→                if (media.getFilePath() != null
411→                    && org.wordpress.android.util.MediaUtils.isLocalFile(media.getUploadState())) {
412→                    File file = new File(media.getFilePath());
413→                    if (!file.exists()) {
414→                        AppLog.w(AppLog.T.MEDIA, "removing nonexistent local media " + media.getFilePath());
415→                        // remove from the store
416→                        mDispatcher.dispatch(MediaActionBuilder.newRemoveMediaAction(media));
417→                        // remove from the passed list
418→                        mediaModels.remove(i);
419→                    }
420→                }
421→            }
422→        }
423→    }
