739→    private void fetchMediaList(boolean loadMore) {
740→        // do not refresh if there is no network
741→        if (!NetworkUtils.isNetworkAvailable(getActivity())) {
742→            updateEmptyView(EmptyViewMessageType.NETWORK_ERROR);
743→            setRefreshing(false);
744→            return;
745→        }
746→
747→        // do not refresh if in search
748→        if (!TextUtils.isEmpty(mSearchTerm)) {
749→            setRefreshing(false);
750→            return;
751→        }
752→
753→        if (!mIsRefreshing) {
754→            setRefreshing(true);
755→            updateEmptyView(EmptyViewMessageType.LOADING);
756→            if (loadMore) {
757→                mSwipeToRefreshHelper.setRefreshing(true);
758→            }
759→
760→            FetchMediaListPayload payload =
761→                    new FetchMediaListPayload(mSite, NUM_MEDIA_PER_FETCH, loadMore, mFilter.toMimeType());
762→            mDispatcher.dispatch(MediaActionBuilder.newFetchMediaListAction(payload));
763→
764→            if (!loadMore) {
765→                // Fetch site to refresh space quota in activity.
766→                mDispatcher.dispatch(SiteActionBuilder.newFetchSiteAction(mSite));
767→            }
768→        }
769→    }
