771→    private void handleFetchAllMediaSuccess(OnMediaListFetched event) {
772→        if (!isAdded()) {
773→            return;
774→        }
775→
776→        // make sure this request was for the current filter
777→        if (event.mimeType != null && MediaFilter.fromMimeType(event.mimeType) != mFilter) {
778→            return;
779→        }
780→
781→        List<MediaModel> filteredMedia = getFilteredMedia();
782→        ensureCorrectState(filteredMedia);
783→        getAdapter().setMediaList(filteredMedia);
784→
785→        boolean hasRetrievedAll = !event.canLoadMore;
786→        getAdapter().setHasRetrievedAll(hasRetrievedAll);
787→
788→        int position = mFilter.getValue();
789→        mFetchedFilters[position] = true;
790→
791→        if (hasRetrievedAll) {
792→            if (mFilter == MediaFilter.FILTER_ALL) {
793→                setHasFetchedMediaForAllFilters();
794→            } else {
795→                mFetchedAllFilters[position] = true;
796→            }
797→        }
798→
799→        setRefreshing(false);
800→        updateEmptyView(EmptyViewMessageType.NO_CONTENT);
801→    }
