803→    private void handleFetchAllMediaError(OnMediaListFetched event) {
804→        MediaErrorType errorType = event.error.type;
805→        AppLog.e(AppLog.T.MEDIA, "Media error occurred: " + errorType);
806→        if (!isAdded()) {
807→            return;
808→        }
809→
810→        if (event.mimeType != null && MediaFilter.fromMimeType(event.mimeType) != mFilter) {
811→            return;
812→        }
813→
814→        int toastResId;
815→        if (errorType == MediaErrorType.AUTHORIZATION_REQUIRED) {
816→            updateEmptyView(EmptyViewMessageType.PERMISSION_ERROR);
817→            toastResId = R.string.media_error_no_permission;
818→        } else {
819→            updateEmptyView(EmptyViewMessageType.GENERIC_ERROR);
820→            toastResId = R.string.error_refresh_media;
821→        }
822→
823→        // only show the toast if the list is NOT empty since the empty view shows the same message
824→        if (!isEmpty()) {
825→            ToastUtils.showToast(getActivity(), getString(toastResId));
826→        }
827→
828→        setRefreshing(false);
829→        setHasFetchedMediaForAllFilters();
830→        getAdapter().setHasRetrievedAll(true);
831→    }
