 311→    private void initViewModels(
 312→            @NonNull ReaderActivityCommentListBinding binding,
 313→            @Nullable Bundle savedInstanceState
 314→    ) {
 315→        mViewModel = new ViewModelProvider(this, mViewModelFactory).get(ReaderCommentListViewModel.class);
