 317→            ScrollPosition content = scrollPositionEvent.getContentIfNotHandled();
 318→            LayoutManager layoutManager = binding.recyclerView.getLayoutManager();
 319→            if (content != null && layoutManager != null) {
 320→                if (content.isSmooth()) {
 321→                    RecyclerView.SmoothScroller smoothScrollerToTop = new LinearSmoothScroller(this) {
 322→                        @Override protected int getVerticalSnapPreference() {
 323→                            return LinearSmoothScroller.SNAP_TO_START;
 324→                        }
 325→                    };
 326→                    smoothScrollerToTop.setTargetPosition(content.getPosition());
 327→                    layoutManager.startSmoothScroll(smoothScrollerToTop);
 328→                } else {
 329→                    ((LinearLayoutManager) layoutManager).scrollToPositionWithOffset(content.getPosition(), 0);
 330→                }
 331→                binding.appbarMain.post(binding.appbarMain::requestLayout);
 332→            }
 333→        });
