 338→        mConversationViewModel.getSnackbarEvents().observe(this, snackbarMessageHolderEvent -> {
 339→            FragmentManager fm = getSupportFragmentManager();
 340→            CommentNotificationsBottomSheetFragment bottomSheet =
 341→                    (CommentNotificationsBottomSheetFragment) fm.findFragmentByTag(NOTIFICATIONS_BOTTOM_SHEET_TAG);
 342→
 343→            if (bottomSheet != null) return;
 344→
 345→            snackbarMessageHolderEvent.applyIfNotHandled(holder -> {
 346→                WPSnackbar.make(binding.coordinatorLayout,
 347→                                  mUiHelpers.getTextOfUiString(ReaderCommentListActivity.this, holder.getMessage()),
 348→                                  Snackbar.LENGTH_LONG)
 349→                          .setAction(
