 353→                                          holder.getButtonTitle())
 354→                                          : null,
 355→                                  v -> holder.getButtonAction().invoke())
 356→                          .show();
 357→                return Unit.INSTANCE;
 358→            });
 359→        });
 360→
 361→        mConversationViewModel.getShowBottomSheetEvent().observe(this, event ->
 362→                event.applyIfNotHandled(isShowingData -> {
 363→                    FragmentManager fm = getSupportFragmentManager();
 364→                    CommentNotificationsBottomSheetFragment bottomSheet =
 365→                            (CommentNotificationsBottomSheetFragment) fm.findFragmentByTag(
 366→                                    NOTIFICATIONS_BOTTOM_SHEET_TAG
 367→                            );
 368→                    if (isShowingData.getShow() && bottomSheet == null) {
 369→                        bottomSheet = CommentNotificationsBottomSheetFragment.newInstance(
 370→                                isShowingData.isReceivingNotifications(),
 371→                                false
 372→                        );
 373→                        bottomSheet.show(fm, NOTIFICATIONS_BOTTOM_SHEET_TAG);
 374→                    } else if (!isShowingData.getShow() && bottomSheet != null) {
 375→                        bottomSheet.dismiss();
 376→                    }
 377→                    return Unit.INSTANCE;
 378→                })
 379→        );
 380→
 381→        if (savedInstanceState != null) {
 382→            mBlogId = savedInstanceState.getLong(ReaderConstants.ARG_BLOG_ID);
 383→            mPostId = savedInstanceState.getLong(ReaderConstants.ARG_POST_ID);
 384→            mRestorePosition = savedInstanceState.getInt(ReaderConstants.KEY_RESTORE_POSITION);
