 386→            mInterceptedUri = savedInstanceState.getString(ReaderConstants.ARG_INTERCEPTED_URI);
 387→            mSource = savedInstanceState.getString(ReaderConstants.ARG_SOURCE);
 388→        } else {
 389→            mBlogId = getIntent().getLongExtra(ReaderConstants.ARG_BLOG_ID, 0);
 390→            mPostId = getIntent().getLongExtra(ReaderConstants.ARG_POST_ID, 0);
