 393→            mCommentId = getIntent().getLongExtra(ReaderConstants.ARG_COMMENT_ID, 0);
 394→            mInterceptedUri = getIntent().getStringExtra(ReaderConstants.ARG_INTERCEPTED_URI);
 395→            mSource = getIntent().getStringExtra(ReaderConstants.ARG_SOURCE);
 396→        }
 397→
 398→        mConversationViewModel.start(mBlogId, mPostId, ThreadedCommentsActionSource.READER_THREADED_COMMENTS);
 399→    }
