 816→    private ReaderCommentAdapter getCommentAdapter(
 817→            @NonNull ReaderActivityCommentListBinding binding,
 818→            @NonNull ReaderIncludeCommentBoxBinding boxBinding
 819→    ) {
 820→        if (mCommentAdapter == null && mPost != null) {
 821→            mCommentAdapter = new ReaderCommentAdapter(WPActivityUtils.getThemedContext(this), mPost);
 822→
 823→            // adapter calls this when user taps reply icon
 824→            mCommentAdapter.setReplyListener(
 825→                    commentId -> setReplyToCommentId(binding, boxBinding, commentId, true)
 826→            );
 827→            // adapter calls this when user taps share icon
 828→            mCommentAdapter.setCommentMenuActionListener(
 829→                    (comment, action) -> performCommentAction(binding, boxBinding, comment, action)
 830→            );
 831→
 832→            // Enable post title click if we came here directly from notifications or deep linking
 833→            if (mDirectOperation != null) {
 834→                mCommentAdapter.enableHeaderClicks();
 835→            }
 836→
 837→            // adapter calls this when data has been loaded & displayed
 838→            mCommentAdapter.setDataLoadedListener(isEmpty -> {
 839→                if (!isFinishing()) {
 840→                    if (isEmpty || !mHasUpdatedComments) {
 841→                        updateComments(binding, mPost, isEmpty, false);
 842→                    } else if (mCommentId > 0 || mDirectOperation != null) {
 843→                        if (mCommentId > 0) {
 844→                            // Scroll to the commentId once if it was passed to this activity
 845→                            smoothScrollToCommentId(binding, boxBinding, mCommentId);
 846→                        }
 847→
 848→                        doDirectOperation(binding, boxBinding);
 849→                    } else if (mRestorePosition > 0) {
 850→                        if (mViewModel != null) {
 851→                            mViewModel.scrollToPosition(mRestorePosition, false);
 852→                        }
 853→                    }
 854→                    mRestorePosition = 0;
 855→                    checkEmptyView(binding, boxBinding);
 856→                }
 857→            });
 858→
 859→            // adapter uses this to request more comments from server when it reaches the end and
 860→            // detects that more comments exist on the server than are stored locally
 861→            mCommentAdapter.setDataRequestedListener(() -> {
 862→                if (!mIsUpdatingComments) {
 863→                    AppLog.i(T.READER, "reader comments > requesting next page of comments");
 864→                    updateComments(binding, mPost, true, true);
 865→                }
 866→            });
 867→        }
 868→        return mCommentAdapter;
 869→    }
