 871→    private void doDirectOperation(
 872→            @NonNull ReaderActivityCommentListBinding binding,
 873→            @NonNull ReaderIncludeCommentBoxBinding boxBinding
 874→    ) {
 875→        if (mDirectOperation != null) {
 876→            switch (mDirectOperation) {
 877→                case COMMENT_JUMP:
 878→                    if (mCommentAdapter != null) {
 879→                        mCommentAdapter.setHighlightCommentId(mCommentId, false);
 880→
 881→                        // clear up the direct operation vars. Only performing it once.
 882→                        mDirectOperation = null;
 883→                        mCommentId = 0;
 884→                    }
 885→                    break;
 886→                case COMMENT_REPLY:
 887→                    setReplyToCommentId(binding, boxBinding, mCommentId, mAccountStore.hasAccessToken());
 888→
 889→                    // clear up the direct operation vars. Only performing it once.
 890→                    mDirectOperation = null;
 891→                    mCommentId = 0;
 892→                    break;
 893→                case COMMENT_LIKE:
 894→                    getCommentAdapter(binding, boxBinding).setHighlightCommentId(mCommentId, false);
 895→                    if (!mAccountStore.hasAccessToken()) {
 896→                        WPSnackbar.make(binding.coordinatorLayout,
 897→                                          R.string.reader_snackbar_err_cannot_like_post_logged_out,
 898→                                          Snackbar.LENGTH_INDEFINITE)
 899→                                  .setAction(R.string.sign_in, mSignInClickListener)
 900→                                  .show();
 901→                    } else if (mPost != null) {
 902→                        ReaderComment comment = ReaderCommentTable.getComment(mPost.blogId, mPost.postId, mCommentId);
 903→                        if (comment == null) {
 904→                            ToastUtils.showToast(
 905→                                    ReaderCommentListActivity.this,
 906→                                    R.string.reader_toast_err_comment_not_found
 907→                            );
 908→                        } else if (comment.isLikedByCurrentUser) {
 909→                            ToastUtils.showToast(
 910→                                    ReaderCommentListActivity.this,
 911→                                    R.string.reader_toast_err_already_liked
 912→                            );
 913→                        } else {
 914→                            long wpComUserId = mAccountStore.getAccount().getUserId();
 915→                            if (ReaderCommentActions.performLikeAction(comment, true, wpComUserId)
 916→                                && getCommentAdapter(binding, boxBinding).refreshComment(mCommentId)) {
 917→                                getCommentAdapter(binding, boxBinding).setAnimateLikeCommentId(mCommentId);
 918→
 919→                                mReaderTracker.trackPost(
 920→                                        AnalyticsTracker.Stat.READER_ARTICLE_COMMENT_LIKED,
 921→                                        mPost
 922→                                );
 923→                                mReaderTracker.trackPost(
 924→                                        AnalyticsTracker.Stat.COMMENT_LIKED,
 925→                                        mPost,
 926→                                        AnalyticsCommentActionSource.READER.toString()
 927→                                );
 928→                            } else {
 929→                                ToastUtils.showToast(
 930→                                        ReaderCommentListActivity.this,
 931→                                        R.string.reader_toast_err_generic
 932→                                );
 933→                            }
 934→                        }
 935→
 936→                        // clear up the direct operation vars. Only performing it once.
 937→                        mDirectOperation = null;
 938→                    }
 939→                    break;
 940→                case POST_LIKE:
 941→                    // nothing special to do in this case
 942→                    break;
 943→            }
 944→        } else {
 945→            mCommentId = 0;
 946→        }
 947→    }
