 984→    /*
 985→     * request comments for this post
 986→     */
 987→    private void updateComments(
 988→            @NonNull ReaderActivityCommentListBinding binding,
 989→            @NonNull ReaderPost post,
 990→            boolean showProgress,
 991→            boolean requestNextPage
 992→    ) {
 993→        if (mIsUpdatingComments) {
 994→            AppLog.w(T.READER, "reader comments > already updating comments");
 995→            setRefreshing(false);
 996→            return;
 997→        }
 998→        if (!NetworkUtils.isNetworkAvailable(this)) {
 999→            AppLog.w(T.READER, "reader comments > no connection, update canceled");
1000→            setRefreshing(false);
1001→            return;
1002→        }
1003→
1004→        if (showProgress) {
1005→            showProgress(binding);
1006→        }
1007→        ReaderCommentService.startService(this, post.blogId, post.postId, requestNextPage);
1008→    }
