1067→    /*
1068→     * submit the text typed into the comment box as a comment on the current post
1069→     */
1070→    private void submitComment(
1071→            @NonNull ReaderActivityCommentListBinding binding,
1072→            @NonNull ReaderIncludeCommentBoxBinding boxBinding
1073→    ) {
1074→        if (mBoxBinding == null) {
1075→            return;
1076→        }
1077→
1078→        final String commentText = EditTextUtils.getText(mBoxBinding.editComment);
1079→        if (TextUtils.isEmpty(commentText)) {
1080→            return;
1081→        }
1082→
1083→        if (!NetworkUtils.checkConnection(this)) {
1084→            return;
1085→        }
1086→
1087→        if (mReplyToCommentId != 0) {
1088→            mReaderTracker.trackPost(AnalyticsTracker.Stat.READER_ARTICLE_COMMENT_REPLIED_TO, mPost);
1089→        } else {
1090→            mReaderTracker.trackPost(AnalyticsTracker.Stat.READER_ARTICLE_COMMENTED_ON, mPost);
1091→        }
1092→
1093→        mBoxBinding.btnSubmitReply.setEnabled(false);
1094→        mBoxBinding.editComment.setEnabled(false);
1095→        mIsSubmittingComment = true;
1096→
1097→        // generate a "fake" comment id to assign to the new comment so we can add it to the db
1098→        // and reflect it in the adapter before the API call returns
1099→        final long fakeCommentId = ReaderCommentActions.generateFakeCommentId();
1100→
1101→        ReaderActions.CommentActionListener actionListener = (succeeded, newComment) -> {
1102→            if (isFinishing()) {
1103→                return;
1104→            }
1105→            mIsSubmittingComment = false;
1106→            mBoxBinding.editComment.setEnabled(true);
1107→            if (succeeded) {
1108→                mBoxBinding.btnSubmitReply.setEnabled(false);
1109→                // stop highlighting the fake comment and replace it with the real one
1110→                getCommentAdapter(binding, boxBinding).setHighlightCommentId(0, false);
1111→                getCommentAdapter(binding, boxBinding).setReplyTargetComment(0);
1112→                getCommentAdapter(binding, boxBinding).replaceComment(fakeCommentId, newComment);
1113→                getCommentAdapter(binding, boxBinding).refreshPost();
1114→                setReplyToCommentId(binding, boxBinding, 0, false);
1115→                mBoxBinding.editComment.getAutoSaveTextHelper().clearSavedText(mBoxBinding.editComment);
1116→            } else {
1117→                mBoxBinding.editComment.setText(commentText);
1118→                mBoxBinding.btnSubmitReply.setEnabled(true);
1119→                getCommentAdapter(binding, boxBinding).removeComment(fakeCommentId);
1120→                ToastUtils.showToast(
1121→                        ReaderCommentListActivity.this, R.string.reader_toast_err_comment_failed,
1122→                        ToastUtils.Duration.LONG);
1123→            }
1124→            checkEmptyView(binding, boxBinding);
1125→        };
1126→
1127→        long wpComUserId = mAccountStore.getAccount().getUserId();
1128→        ReaderComment newComment = ReaderCommentActions.submitPostComment(
1129→                mPost,
1130→                fakeCommentId,
1131→                commentText,
1132→                mReplyToCommentId,
1133→                actionListener,
1134→                wpComUserId);
1135→
1136→        if (newComment != null) {
1137→            mBoxBinding.editComment.setText(null);
1138→            // add the "fake" comment to the adapter, highlight it, and show a progress bar
1139→            // next to it while it's submitted
1140→            getCommentAdapter(binding, boxBinding).setHighlightCommentId(newComment.commentId, true);
1141→            getCommentAdapter(binding, boxBinding).setReplyTargetComment(0);
1142→            getCommentAdapter(binding, boxBinding).addComment(newComment);
1143→            // make sure it's scrolled into view
1144→            scrollToCommentId(binding, boxBinding, fakeCommentId);
1145→            checkEmptyView(binding, boxBinding);
1146→        }
1147→    }
