287→                if (isFetching) {
288→                    mFilteredRecyclerView.showLoadingProgress();
289→                }
290→            } else {
291→                boolean isFetching = mOnFetchPeopleListener.onFetchFirstPage(mPeopleListFilter);
292→                if (isFetching) {
293→                    mFilteredRecyclerView.updateEmptyView(EmptyViewMessageType.LOADING);
294→                } else {
295→                    mFilteredRecyclerView.hideEmptyView();
296→                    mFilteredRecyclerView.setRefreshing(false);
297→                }
298→                refreshPeopleList(isFetching);
299→            }
300→        }
