125→
126→        viewModel.listStatus.observe(viewLifecycleOwner, Observer { listStatus ->
127→            listStatus?.let {
128→                if (isAdded && view != null) {
129→                    swipeToRefreshHelper.isRefreshing = listStatus == HistoryListStatus.FETCHING
