 95→    private fun init() {
 96→        updateUiState(FullScreenLoadingUiState)
 97→        launch {
 98→            scanStateModel = scanStore.getScanStateForSite(this@ScanViewModel.site)
 99→            scanStateModel?.let {
100→                if (fixableThreatIds.isNotEmpty()) fetchFixThreatsStatus(fixableThreatIds, isInvokedByUser = false)
101→            }
102→            fetchScanState(isInvokedFromInit = true)
103→        }
