106→    private suspend fun fetchScanState(
107→        invokedByUser: Boolean = false,
108→        isRetry: Boolean = false,
109→        isInvokedFromInit: Boolean = false
110→    ) {
111→        if (isRetry) delay(RETRY_DELAY)
112→
113→        fetchScanStateUseCase.fetchScanState(site = site, startWithDelay = invokedByUser)
114→            .collect { state ->
115→                when (state) {
116→                    is FetchScanState.Success -> {
117→                        scanStateModel = state.scanStateModel
118→                        updateUiState(buildContentUiState(state.scanStateModel))
119→                        if (state.scanStateModel.state in listOf(State.UNAVAILABLE, State.UNKNOWN)) {
120→                            scanTracker.trackOnError(ErrorAction.FETCH_SCAN_STATE, ErrorCause.OTHER)
121→                            updateUiState(ErrorUiState.ScanRequestFailed(::onContactSupportClicked))
122→                        } else if (invokedByUser && state.scanStateModel.state == State.IDLE) {
123→                            showScanFinishedMessage(state.scanStateModel)
124→                        }
125→                    }
126→
127→                    is FetchScanState.Failure.NetworkUnavailable -> {
128→                        scanTracker.trackOnError(ErrorAction.FETCH_SCAN_STATE, ErrorCause.OFFLINE)
129→                        scanStateModel?.takeIf { !isInvokedFromInit }
130→                            ?.let {
131→                                updateSnackbarMessageEvent(UiStringRes(R.string.error_generic_network))
132→                            }
133→                            ?: updateUiState(ErrorUiState.NoConnection(::onRetryClicked))
134→                    }
135→
136→                    is FetchScanState.Failure.MultisiteNotSupported ->
137→                        updateUiState(ErrorUiState.MultisiteNotSupported)
138→
139→                    is FetchScanState.Failure.VaultPressActiveOnSite ->
140→                        updateUiState(ErrorUiState.VaultPressActiveOnSite(::onVisitVaultPressDashboardClicked))
141→
142→                    is FetchScanState.Failure.RemoteRequestFailure -> {
143→                        scanTracker.trackOnError(ErrorAction.FETCH_SCAN_STATE, ErrorCause.REMOTE)
144→                        scanStateModel?.takeIf { !isInvokedFromInit }
145→                            ?.let {
146→                                updateSnackbarMessageEvent(UiStringRes(R.string.request_failed_message))
147→                            }
148→                            ?: updateUiState(ErrorUiState.GenericRequestFailed(::onContactSupportClicked))
149→                    }
150→                }
151→            }
152→    }
