160→                )
161→
162→                1 -> htmlMessageUtils.getHtmlMessageFromStringFormatResId(
163→                    R.string.scan_finished_potential_threats_found_message_singular
164→                )
165→
166→                else -> htmlMessageUtils.getHtmlMessageFromStringFormatResId(
167→                    R.string.scan_finished_potential_threats_found_message_plural,
168→                    "$threatsCount"
169→                )
170→            }
171→        )
172→        updateSnackbarMessageEvent(message)
173→    }
