175→    private fun startScan() {
176→        launch {
177→            startScanUseCase.startScan(site)
178→                .collect { state ->
179→                    when (state) {
180→                        is StartScanState.ScanningStateUpdatedInDb ->
181→                            updateUiState(buildContentUiState(state.model))
182→
183→                        is StartScanState.Success -> fetchScanState(invokedByUser = true)
184→
185→                        is StartScanState.Failure.NetworkUnavailable -> {
186→                            scanTracker.trackOnError(ErrorAction.SCAN, ErrorCause.OFFLINE)
187→                            updateSnackbarMessageEvent(UiStringRes(R.string.error_generic_network))
188→                        }
189→                        is StartScanState.Failure.RemoteRequestFailure -> {
190→                            scanTracker.trackOnError(ErrorAction.SCAN, ErrorCause.REMOTE)
191→                            updateUiState(ContentUiState(emptyList()))
192→                            updateUiState(ErrorUiState.ScanRequestFailed(::onContactSupportClicked))
193→                        }
194→                    }
195→                }
196→        }
197→    }
