199→    private fun fixAllThreats() {
200→        scanTracker.trackOnFixAllThreatsConfirmed()
201→        launch {
202→            when (fixThreatsUseCase.fixThreats(remoteSiteId = site.siteId, fixableThreatIds = fixableThreatIds)) {
203→                is FixThreatsState.Success -> {
204→                    val someOrAllThreatFixed = fetchFixThreatsStatus(fixableThreatIds, isInvokedByUser = true)
205→                    if (someOrAllThreatFixed) fetchScanState()
206→                }
207→                is FixThreatsState.Failure.NetworkUnavailable -> {
208→                    scanTracker.trackOnError(ErrorAction.FIX_ALL, ErrorCause.OFFLINE)
209→                    updateSnackbarMessageEvent(UiStringRes(R.string.error_generic_network))
210→                }
211→                is FixThreatsState.Failure.RemoteRequestFailure -> {
212→                    scanTracker.trackOnError(ErrorAction.FIX_ALL, ErrorCause.REMOTE)
213→                    updateSnackbarMessageEvent(UiStringRes(R.string.threat_fix_all_error_message))
214→                }
215→            }
216→        }
217→    }
218→
219→    private suspend fun fetchFixThreatsStatus(fixableThreatIds: List<Long>, isInvokedByUser: Boolean): Boolean {
220→        var someOrAllThreatFixed = false
221→
222→        @StringRes var messageRes: Int? = null
223→        fetchFixThreatsStatusUseCase.fetchFixThreatsStatus(
224→            remoteSiteId = site.siteId,
225→            fixableThreatIds = fixableThreatIds
226→        ).collect { status ->
227→            var fixingThreatIds = emptyList<Long>()
228→            when (status) {
229→                is FetchFixThreatsState.NotStarted -> { // Do nothing
230→                }
231→                is FetchFixThreatsState.InProgress -> {
232→                    fixingThreatIds = status.threatIds
233→                }
234→                is FetchFixThreatsState.Complete -> {
235→                    someOrAllThreatFixed = true
236→                    messageRes = if (status.fixedThreatsCount == 1) {
237→                        R.string.threat_fix_all_status_success_message_singular
238→                    } else R.string.threat_fix_all_status_success_message_plural
239→                }
240→                is FetchFixThreatsState.Failure.NetworkUnavailable -> {
241→                    scanTracker.trackOnError(ErrorAction.FETCH_FIX_THREAT_STATUS, ErrorCause.OFFLINE)
242→                    messageRes = R.string.error_generic_network
243→                }
244→                is FetchFixThreatsState.Failure.RemoteRequestFailure -> {
245→                    scanTracker.trackOnError(ErrorAction.FETCH_FIX_THREAT_STATUS, ErrorCause.REMOTE)
246→                    messageRes = R.string.threat_fix_all_status_error_message
247→                }
248→                is FetchFixThreatsState.Failure.FixFailure -> {
249→                    if (status.mightBeMissingCredentials) {
250→                        scanTracker.trackOnError(ErrorAction.FETCH_FIX_THREAT_STATUS, ErrorCause.ALL_THREATS_NOT_FIXED)
251→                    } else {
252→                        scanTracker.trackOnError(ErrorAction.FETCH_FIX_THREAT_STATUS, ErrorCause.OTHER)
253→                    }
254→                    if (!status.containsOnlyErrors) {
255→                        someOrAllThreatFixed = true
256→                    } else {
257→                        messageRes = R.string.threat_fix_all_status_error_message
258→                    }
259→                }
260→            }
261→
262→            val shouldUpdateUi = status is FetchFixThreatsState.InProgress || status is FetchFixThreatsState.Complete
263→            if (shouldUpdateUi) {
264→                updateUiState(
265→                    buildContentUiState(model = requireNotNull(scanStateModel), fixingThreatIds = fixingThreatIds)
266→                )
267→            }
268→
269→            if (isInvokedByUser) messageRes?.let { updateSnackbarMessageEvent(UiStringRes(it)) }
270→        }
271→
272→        return someOrAllThreatFixed
273→    }
