217→    public void categoryAdded(TermModel newCategory) {
218→        if (!NetworkUtils.checkConnection(this)) {
219→            mEmptyView.setText(R.string.no_network_title);
220→            return;
221→        }
222→        // Save selected categories
223→        updateSelectedCategoryList();
224→        mListScrollPositionManager.saveScrollOffset();
225→
226→        mSwipeToRefreshHelper.setRefreshing(true);
227→        RemoteTermPayload payload = new RemoteTermPayload(newCategory, mSite);
228→        mDispatcher.dispatch(TaxonomyActionBuilder.newPushTermAction(payload));
