350→    private fun moveActiveThemeToFront(themes: MutableList<ThemeModel>) {
351→        if (themes.isEmpty() || TextUtils.isEmpty(currentThemeId)) {
352→            return
353→        }
354→
355→        // find the index of the active theme
356→        var activeThemeIndex = 0
357→        for (theme in themes) {
358→            if (currentThemeId == theme.themeId) {
359→                theme.active = true
360→                activeThemeIndex = themes.indexOf(theme)
361→                break
362→            }
363→        }
364→
365→        // move active theme to front of list
366→        if (activeThemeIndex > 0) {
367→            themes.add(0, themes.removeAt(activeThemeIndex))
368→        }
369→    }
