379→    private fun removeDuplicateThemes(wpComThemes: MutableList<ThemeModel>, uploadedThemes: List<ThemeModel>) {
380→        if (wpComThemes.isEmpty() || uploadedThemes.isEmpty()) {
381→            return
382→        }
383→
384→        for (uploadedTheme in uploadedThemes) {
385→            val wpComIterator = wpComThemes.iterator()
386→            while (wpComIterator.hasNext()) {
387→                val wpComTheme = wpComIterator.next()
388→                if (StringUtils.equals(wpComTheme.themeId, uploadedTheme.themeId.replace("-wpcom", ""))) {
389→                    wpComIterator.remove()
390→                    break
391→                }
392→            }
393→        }
394→    }
