131→            override fun onSuccess(peopleList: List<Person>, isEndOfList: Boolean) {
132→                val existingRevisions = _revisions.value ?: return
133→                val updatedRevisions = mutableListOf<HistoryListItem>()
134→                revisionsList.clear()
