 553→    private void performCommentAction(
 554→            @NonNull ReaderActivityCommentListBinding binding,
 555→            @NonNull ReaderIncludeCommentBoxBinding boxBinding,
 556→            @NonNull ReaderComment comment,
 557→            @NonNull ReaderCommentMenuActionType action
 558→    ) {
 559→        switch (action) {
 560→            case EDIT:
 561→                SiteModel postSite = mSiteStore.getSiteBySiteId(comment.blogId);
 562→                if (postSite != null) {
 563→                    openCommentEditor(comment, postSite);
 564→                }
 565→                break;
 566→            case UNAPPROVE:
 567→                moderateComment(
 568→                        binding,
 569→                        boxBinding,
 570→                        comment,
 571→                        CommentStatus.UNAPPROVED,
 572→                        R.string.comment_unapproved,
 573→                        Stat.COMMENT_UNAPPROVED
 574→                );
 575→                break;
 576→            case SPAM:
 577→                moderateComment(
 578→                        binding,
 579→                        boxBinding,
 580→                        comment,
 581→                        CommentStatus.SPAM,
 582→                        R.string.comment_spammed,
 583→                        Stat.COMMENT_SPAMMED
 584→                );
 585→                break;
 586→            case TRASH:
 587→                moderateComment(
 588→                        binding,
 589→                        boxBinding,
 590→                        comment,
 591→                        CommentStatus.TRASH,
 592→                        R.string.comment_trashed,
 593→                        Stat.COMMENT_TRASHED
 594→                );
 595→                break;
 596→            case SHARE:
 597→                shareComment(comment.getShortUrl());
 598→                break;
 599→            case APPROVE:
 600→            case DIVIDER_NO_ACTION:
 601→                break;
 602→        }
 603→    }
