 915→                            if (ReaderCommentActions.performLikeAction(comment, true, wpComUserId)
 916→                                && getCommentAdapter(binding, boxBinding).refreshComment(mCommentId)) {
 917→                                getCommentAdapter(binding, boxBinding).setAnimateLikeCommentId(mCommentId);
 918→
 919→                                mReaderTracker.trackPost(
 920→                                        AnalyticsTracker.Stat.READER_ARTICLE_COMMENT_LIKED,
 921→                                        mPost
