1149→    private int getCurrentPosition(@NonNull ReaderActivityCommentListBinding binding) {
1150→        if (hasCommentAdapter()) {
1151→            LinearLayoutManager layoutManager = (LinearLayoutManager) binding.recyclerView.getLayoutManager();
1152→            if (layoutManager != null) {
1153→                return layoutManager.findFirstVisibleItemPosition();
1154→            } else {
1155→                return 0;
1156→            }
1157→        } else {
1158→            return 0;
1159→        }
1160→    }
