312→                break;
313→            case SUBSCRIBERS:
314→                peopleList = PeopleTable.getFollowers(mSite.getId());
315→                break;
316→            case EMAIL_SUBSCRIBERS:
317→                peopleList = PeopleTable.getEmailFollowers(mSite.getId());
318→                break;
319→            case VIEWERS:
320→                peopleList = PeopleTable.getViewers(mSite.getId());
321→                break;
322→            default:
323→                peopleList = new ArrayList<>();
324→                break;
325→        }
326→        PeopleAdapter peopleAdapter = (PeopleAdapter) mFilteredRecyclerView.getAdapter();
327→        if (peopleAdapter == null) {
328→            peopleAdapter = new PeopleAdapter(getActivity(), peopleList);
329→            mFilteredRecyclerView.setAdapter(peopleAdapter);
330→        } else {
331→            peopleAdapter.setPeopleList(peopleList);
332→        }
333→
334→        if (!peopleList.isEmpty()) {
335→            // if the list is not empty, don't show any message
336→            mFilteredRecyclerView.hideEmptyView();
337→            mFilteredRecyclerView.setToolbarScrollFlags(AppBarLayout.LayoutParams.SCROLL_FLAG_SCROLL);
338→            mActionableEmptyView.setVisibility(View.GONE);
339→        } else if (!isFetching) {
340→            // if we are not fetching and list is empty, show no content message
341→            mFilteredRecyclerView.updateEmptyView(EmptyViewMessageType.NO_CONTENT);
342→        }
343→    }
344→
345→    // Refresh the role display names after user roles is fetched
346→    public void refreshUserRoles() {
347→        if (mFilteredRecyclerView == null) {
348→            // bail when list is not available
349→            return;
350→        }
351→
352→        PeopleAdapter peopleAdapter = (PeopleAdapter) mFilteredRecyclerView.getAdapter();
353→        if (peopleAdapter != null) {
354→            peopleAdapter.refreshUserRoles();
355→            peopleAdapter.notifyDataSetChanged();
356→        }
357→    }
