359→    public void fetchingRequestFinished(PeopleListFilter filter, boolean isFirstPage, boolean isSuccessful) {
360→        if (mPeopleListFilter == filter) {
361→            if (isFirstPage) {
362→                mFilteredRecyclerView.setRefreshing(false);
363→                if (!isSuccessful) {
364→                    mFilteredRecyclerView.updateEmptyView(EmptyViewMessageType.GENERIC_ERROR);
365→                }
366→            } else {
367→                mFilteredRecyclerView.hideLoadingProgress();
368→            }
369→        }
370→    }
